<template>
  <div class="w-full h-full">
    <div class="w-3/4 h-full mx-auto flex flex-col">
      <!-- 导航栏 -->
      <div
        class="
          w-full
          max-w-full
          mx-auto
          mt-10
          rounded
          border-b-4
          shadow-xl
          rounded-xl
          flex
          space-x-4
        "
      >
        <div
          @click.stop="
            mode_current = 'like';
            current_type_id = -1;
          "
          :class="[current_type_id == -1 ? 'bg-gray-300' : '']"
          class="cursor-pointer p-4 justify-center bg-gray-100"
        >
          <font-awesome-icon class="text-pink-600" icon="heart" />
        </div>
        <ul
          class="
            w-full
            max-w-full
            flex
            text-center
            justify-between
            flex-wrap
            space-x-2
            px-1
            pt-2
            overflow-x-scroll
          "
        >
          <li
            v-for="(item, index) in submode"
            :key="submode + index"
            class="
              cursor-pointer
              whitespace-nowrap
              py-2
              font-semibold
              text-gray-800
              rounded-t
              opacity-50
            "
            :class="[
              current_type_id == index
                ? 'border-blue-400 border-b-4 -mb-px opacity-100'
                : '',
            ]"
            @click.stop="
              mode_current = item;
              current_type_id = index;
            "
          >
            {{ item }}
          </li>
        </ul>
      </div>

      <!-- 内容框 -->
      <div class="h-5/6 w-full mt-10 mx-auto">
        <div class="flex w-full h-full space-x-5">
          <div
            id="content_table"
            class="flex-grow relative overflow-y-auto bg-gray-100"
            style="scroll-behavior: smooth"
          >
            <div
              class="absolute flex w-full h-full justify-center items-center"
              v-if="showLikeMessage"
            >
              <div class="font-normal antialiased text-2xl">
                单击卡片图标即可添加
              </div>
            </div>
            <div
              class="
                w-full
                p-3
                mb-3
                grid
                gap-8
                bg-white
                grid-cols-1
                lg:grid-cols-4
              "
              v-for="(menu, menu_i) in content"
              :key="'menu' + menu_i"
            >
              <div
                class="
                  w-full
                  p-3
                  bg-white
                  flex-none
                  border-2
                  shadow-xl
                  cursor-pointer
                "
                v-for="(item, item_i) in menu.data"
                :key="'item' + item_i"
              >
                <div class="flex flex-nowrap w-full h-full">
                  <img
                    @click.stop="
                      addLike(item['name'], item['path'], item['icon'])
                    "
                    class="w-6 h-6 flex-none"
                    :src="item['icon']"
                  />
                  <div
                    class="ml-1 flex-grow text-center"
                    @mouseenter="openMessage($event, item['path'])"
                    @mouseleave="hideMessage($event, item['path'])"
                    @click.stop="openTab(item['path'], item['icon'])"
                  >
                    {{ item["name"] }}
                  </div>
                </div>
              </div>
            </div>
          </div>
          <div class="flex-none">
            <!-- 时间线，加在内容框的左边 -->
            <com-timeline :timeline="timeline" :cb="switch_content" />
          </div>
        </div>
      </div>

      <!-- 消息体  -->
      <message ref="message" :description="description" v-show="showMessage" />
    </div>
  </div>
</template>

<script>
import { createPopper } from "@popperjs/core";

import ComTimeline from "@/components/Timeline.vue";
import Message from "./message.vue";

const MENU_DATA = require("@/configs/compass.js").MENU_DATA;

export default {
  name: "MenuPage",
  components: {
    ComTimeline,
    Message,
  },
  data() {
    return {
      // current: "编程语言",
      description: "这是一段简介",
      messageDOM: undefined, // message
      showMessage: false,
      current_type_id: 0, // 默认第一个, 用来控制菜单栏样式的
      mode_current: undefined, // 当前的子种类，如果是like，就是用户自定义的部分
    };
  },
  computed: {
    showLikeMessage() {
      return this.current == "like" && this.content[0].data.length === 0;
    },
    current() {
      return this.mode_current || this.submode[0];
    },
    submode() {
      let res = [];
      for (let i of MENU_DATA) {
        res.push(i["meta"]);
      }
      return res;
    },
    timeline() {
      // 当前目录下的timeline
      if (this.current == "like") {
        return []; // 暂时不给tag
      }
      for (let item of MENU_DATA) {
        if (item["meta"] === this.current) {
          let res = [];
          for (let sub of item["content"]) {
            res.push(sub["tag"]);
          }
          return res;
        }
      }
      return [];
    },
    content() {
      if (this.current == "like") {
        // 个人收藏
        let res = this.$store.getters["like/record"];
        return res;
      }
      for (let item of MENU_DATA) {
        if (item["meta"] === this.current) {
          return item["content"];
        }
      }
      return [];
    },
  },
  beforeCreate() {
    this.$store.dispatch("like/initLike");
  },
  methods: {
    addLike(name, path, icon) {
      this.$store
        .dispatch("like/addLike", {
          name: name,
          path: path,
          icon: icon,
        })
        .then((resp) => {
          console.log("添加收藏成功");
        })
        .catch((err) => {
          console.log(err);
        });
    },
    openTab(url, icon) {
      this.$store.dispatch("tab/addItem", { url: url, icon: icon });
    },
    openMessage(event, url) {
      this.showMessage = true;
      this.messageDOM = createPopper(event.target, this.$refs.message.$el, {
        placement: "top",
        positionFixed: true,
      });
    },
    hideMessage(event, url) {
      this.showMessage = false;
      this.messageDOM.destroy();
    },
    /**
     * 用于滚动内容框
     */
    switch_content(index) {
      // 获取ref=content_table中第index个元素，获取content_table的clientY，将目标元素往上移动
      let content_table = document.querySelector("#content_table");
      let target = document.querySelector(
        `#content_table > div:nth-child(${index + 1})`
      );
      // let content_target = content_
      // console.log(content_table.getBoundingClientRect().top, target.getBoundingClientRect().top);
      // content_table.clientTop
      content_table.scrollTop +=
        target.getBoundingClientRect().top -
        content_table.getBoundingClientRect().top -
        12;
    },
  },
};
</script>